ORDER BY id ASC

mapper.insert:
INSERT INTO tb_accident_claim_doc (
    claim_id, doc_type, doc_name, is_required, is_submitted, file_id, notes, created_at
) VALUES (
    #{claimId}, #{docType}, #{docName}, #{isRequired}, #{isSubmitted}, #{fileId}, #{notes}, GETDATE()
